  1→//! Gate types for defining quality checks and capturing their results.
  2→
  3→use chrono::{DateTime, Utc};
  4→use schemars::JsonSchema;
  5→use serde::{Deserialize, Serialize};
  6→
  7→/// The kind of gate to evaluate.
  8→///
  9→/// Uses internal tagging (`#[serde(tag = "kind")]`) so TOML output includes
 10→/// a `kind = "Command"` or `kind = "AlwaysPass"` discriminator field.
 11→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize, JsonSchema)]
 12→#[serde(tag = "kind")]
 13→pub enum GateKind {
 14→    /// A gate that runs a shell command and checks its exit code.
 15→    Command {
 16→        /// The shell command to execute.
 17→        cmd: String,
 18→    },
 19→
 20→    /// A gate that always passes — useful for placeholder or manual gates.
 21→    AlwaysPass,
 22→}
 23→
 24→inventory::submit! {
 25→    crate::schema_registry::SchemaEntry {
 26→        name: "gate-kind",
 27→        generate: || schemars::schema_for!(GateKind),
 28→    }
 29→}
 30→
 31→/// The result of evaluating a gate.
 32→///
 33→/// Captures whether the gate passed, the command output (if any), timing,
 34→/// and which kind of gate produced this result (self-describing via `kind`).
 35→#[derive(Debug, Clone, Serialize, Deserialize, JsonSchema)]
 36→pub struct GateResult {
 37→    /// Whether the gate passed.
 38→    pub passed: bool,
 39→
 40→    /// Which gate kind produced this result.
 41→    pub kind: GateKind,
 42→
 43→    /// Standard output captured from the gate command.
 44→    /// Omitted from serialized output when empty.
 45→    #[serde(skip_serializing_if = "String::is_empty", default)]
 46→    pub stdout: String,
 47→
 48→    /// Standard error captured from the gate command.
 49→    /// Omitted from serialized output when empty.
 50→    #[serde(skip_serializing_if = "String::is_empty", default)]
 51→    pub stderr: String,
 52→
 53→    /// Exit code from the gate command, if applicable.
 54→    /// Omitted from serialized output when `None` (e.g., for `AlwaysPass` gates).
 55→    #[serde(skip_serializing_if = "Option::is_none", default)]
 56→    pub exit_code: Option<i32>,
 57→
 58→    /// How long the gate took to evaluate, in milliseconds.
 59→    pub duration_ms: u64,
 60→
 61→    /// When the gate evaluation completed.
 62→    pub timestamp: DateTime<Utc>,
 63→}
 64→
 65→inventory::submit! {
 66→    crate::schema_registry::SchemaEntry {
 67→        name: "gate-result",
 68→        generate: || schemars::schema_for!(GateResult),
 69→    }
 70→}
 71→
 72→#[cfg(test)]
 73→mod tests {
 74→    use super::*;
 75→
 76→    #[test]
 77→    fn gate_kind_command_toml_roundtrip() {
 78→        let kind = GateKind::Command {
 79→            cmd: "cargo test".to_string(),
 80→        };
 81→
 82→        let toml_str = toml::to_string(&kind).expect("serialize to TOML");
 83→        assert!(
 84→            toml_str.contains(r#"kind = "Command""#),
 85→            "TOML should contain kind = \"Command\", got:\n{toml_str}"
 86→        );
 87→        assert!(
 88→            toml_str.contains(r#"cmd = "cargo test""#),
 89→            "TOML should contain cmd = \"cargo test\", got:\n{toml_str}"
 90→        );
 91→
 92→        let roundtripped: GateKind = toml::from_str(&toml_str).expect("deserialize from TOML");
 93→        let re_serialized = toml::to_string(&roundtripped).expect("re-serialize to TOML");
 94→        assert_eq!(toml_str, re_serialized);
 95→    }
 96→
 97→    #[test]
 98→    fn gate_kind_always_pass_toml_roundtrip() {
 99→        let kind = GateKind::AlwaysPass;
100→
101→        let toml_str = toml::to_string(&kind).expect("serialize to TOML");
102→        assert!(
103→            toml_str.contains(r#"kind = "AlwaysPass""#),
104→            "TOML should contain kind = \"AlwaysPass\", got:\n{toml_str}"
105→        );
106→
107→        let roundtripped: GateKind = toml::from_str(&toml_str).expect("deserialize from TOML");
108→        let re_serialized = toml::to_string(&roundtripped).expect("re-serialize to TOML");
109→        assert_eq!(toml_str, re_serialized);
110→    }
111→
112→    #[test]
113→    fn gate_result_json_skips_empty_fields() {
114→        let result = GateResult {
115→            passed: true,
116→            kind: GateKind::AlwaysPass,
117→            stdout: String::new(),
118→            stderr: String::new(),
119→            exit_code: None,
120→            duration_ms: 0,
121→            timestamp: Utc::now(),
122→        };
123→
124→        let json = serde_json::to_string(&result).expect("serialize to JSON");
125→        assert!(
126→            !json.contains("stdout"),
127→            "JSON should omit empty stdout, got:\n{json}"
128→        );
129→        assert!(
130→            !json.contains("stderr"),
131→            "JSON should omit empty stderr, got:\n{json}"
132→        );
133→        assert!(
134→            !json.contains("exit_code"),
135→            "JSON should omit None exit_code, got:\n{json}"
136→        );
137→    }
138→
139→    #[test]
140→    fn gate_result_json_includes_populated_fields() {
141→        let result = GateResult {
142→            passed: true,
143→            kind: GateKind::Command {
144→                cmd: "cargo test".to_string(),
145→            },
146→            stdout: "all tests passed".to_string(),
147→            stderr: "warning: unused variable".to_string(),
148→            exit_code: Some(0),
149→            duration_ms: 1500,
150→            timestamp: Utc::now(),
151→        };
152→
153→        let json = serde_json::to_string(&result).expect("serialize to JSON");
154→        assert!(
155→            json.contains("stdout"),
156→            "JSON should include populated stdout, got:\n{json}"
157→        );
158→        assert!(
159→            json.contains("stderr"),
160→            "JSON should include populated stderr, got:\n{json}"
161→        );
162→        assert!(
163→            json.contains("exit_code"),
164→            "JSON should include Some exit_code, got:\n{json}"
165→        );
166→    }
167→}
