 1→//! Criterion types for defining acceptance criteria on specs.
 2→
 3→use schemars::JsonSchema;
 4→use serde::{Deserialize, Serialize};
 5→
 6→/// A single acceptance criterion attached to a spec.
 7→///
 8→/// Each criterion has a name, description, and an optional shell command
 9→/// that can verify it programmatically. When `cmd` is `None`, the criterion
10→/// is evaluated manually (or in future phases, via an agent `prompt` field).
11→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize, JsonSchema)]
12→#[serde(deny_unknown_fields)]
13→pub struct Criterion {
14→    /// Human-readable name for this criterion.
15→    pub name: String,
16→
17→    /// Detailed description of what this criterion checks.
18→    pub description: String,
19→
20→    /// Optional shell command to verify this criterion.
21→    /// Omitted from serialized output when `None`.
22→    // Forward-compatible: a future `prompt` field will support agent-based evaluation.
23→    #[serde(skip_serializing_if = "Option::is_none", default)]
24→    pub cmd: Option<String>,
25→}
26→
27→inventory::submit! {
28→    crate::schema_registry::SchemaEntry {
29→        name: "criterion",
30→        generate: || schemars::schema_for!(Criterion),
31→    }
32→}
33→
34→#[cfg(test)]
35→mod tests {
36→    use super::*;
37→
38→    #[test]
39→    fn criterion_cmd_none_is_valid() {
40→        let criterion = Criterion {
41→            name: "builds cleanly".to_string(),
42→            description: "The project compiles without warnings".to_string(),
43→            cmd: None,
44→        };
45→
46→        let toml_str = toml::to_string(&criterion).expect("serialize to TOML");
47→        assert!(
48→            !toml_str.contains("cmd"),
49→            "TOML should omit absent cmd, got:\n{toml_str}"
50→        );
51→
52→        let roundtripped: Criterion = toml::from_str(&toml_str).expect("deserialize from TOML");
53→        assert_eq!(criterion, roundtripped);
54→    }
55→
56→    #[test]
57→    fn criterion_cmd_some_is_valid() {
58→        let criterion = Criterion {
59→            name: "tests pass".to_string(),
60→            description: "All unit tests pass".to_string(),
61→            cmd: Some("cargo test".to_string()),
62→        };
63→
64→        let toml_str = toml::to_string(&criterion).expect("serialize to TOML");
65→        assert!(
66→            toml_str.contains(r#"cmd = "cargo test""#),
67→            "TOML should include cmd, got:\n{toml_str}"
68→        );
69→
70→        let roundtripped: Criterion = toml::from_str(&toml_str).expect("deserialize from TOML");
71→        assert_eq!(criterion, roundtripped);
72→    }
73→}
