629→                Criterion {
630→                    name: "fails".to_string(),
631→                    description: "will fail".to_string(),
632→                    cmd: Some("false".to_string()),
633→                    timeout: None,
634→                },
635→            ],
636→        };
637→
638→        let summary = evaluate_all(&spec, dir.path(), None, None);
639→
640→        assert_eq!(summary.spec_name, "mixed");
641→        assert_eq!(summary.passed, 1, "one criterion should pass");
642→        assert_eq!(summary.failed, 1, "one criterion should fail");
643→        assert_eq!(summary.skipped, 1, "one criterion should be skipped");
644→        assert_eq!(summary.results.len(), 3);
645→
646→        // Check descriptive criterion was skipped
647→        assert!(summary.results[1].result.is_none());
648→    }
649→
650→    #[test]
651→    fn evaluate_all_captures_spawn_failure() {
652→        let dir = tempfile::tempdir().unwrap();
653→        let spec = Spec {
654→            name: "bad-cmd".to_string(),
655→            description: String::new(),
656→            criteria: vec![Criterion {
657→                name: "impossible".to_string(),
658→                description: "nonexistent binary".to_string(),
659→                cmd: Some("/nonexistent/binary/that/does/not/exist".to_string()),
660→                timeout: None,
661→            }],
662→        };
663→
664→        let summary = evaluate_all(&spec, dir.path(), None, None);
665→
666→        assert_eq!(summary.failed, 1, "spawn failure should count as failed");
667→        assert_eq!(summary.passed, 0);
668→        let result = summary.results[0].result.as_ref().unwrap();
669→        assert!(!result.passed);
670→    }
671→}
