  1→//! Spec parsing, validation, and directory scanning.
  2→//!
  3→//! Handles loading, parsing, and validating specifications
  4→//! that define what should be built and their acceptance criteria.
  5→
  6→use std::collections::HashSet;
  7→use std::fmt;
  8→use std::path::Path;
  9→
 10→use assay_types::Spec;
 11→
 12→use crate::error::{AssayError, Result};
 13→
 14→/// A single validation issue in a spec file.
 15→#[derive(Debug, Clone)]
 16→pub struct SpecError {
 17→    /// The field path (e.g., "name", "criteria").
 18→    pub field: String,
 19→    /// What's wrong.
 20→    pub message: String,
 21→}
 22→
 23→impl fmt::Display for SpecError {
 24→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
 25→        write!(f, "{}: {}", self.field, self.message)
 26→    }
 27→}
 28→
 29→/// Result of scanning a directory for spec files.
 30→#[derive(Debug)]
 31→pub struct ScanResult {
 32→    /// Successfully parsed and validated specs, sorted by filename.
 33→    /// Each entry is `(slug, spec)` where slug is the filename without extension.
 34→    /// Specs with duplicate `name` fields are removed and reported in `errors`.
 35→    pub specs: Vec<(String, Spec)>,
 36→    /// Errors from files that failed to parse, validate, or read.
 37→    pub errors: Vec<AssayError>,
 38→}
 39→
 40→/// Parse a spec from a TOML string without validation.
 41→///
 42→/// Returns the raw `toml::de::Error` on failure, preserving line/column
 43→/// information. For file-based loading with automatic validation, see
 44→/// [`load()`] which reads from disk and calls [`validate()`].
 45→pub fn from_str(s: &str) -> std::result::Result<Spec, toml::de::Error> {
 46→    toml::from_str(s)
 47→}
 48→
 49→/// Validate a parsed spec for semantic correctness.
 50→///
 51→/// Collects **all** validation errors at once so the user can fix
 52→/// everything in a single pass. Returns `Ok(())` when valid,
 53→/// `Err(errors)` with every issue found otherwise.
 54→pub fn validate(spec: &Spec) -> std::result::Result<(), Vec<SpecError>> {
 55→    let mut errors = Vec::new();
 56→
 57→    if spec.name.trim().is_empty() {
 58→        errors.push(SpecError {
 59→            field: "name".into(),
 60→            message: "required, must not be empty".into(),
 61→        });
 62→    }
 63→
 64→    if spec.criteria.is_empty() {
 65→        errors.push(SpecError {
 66→            field: "criteria".into(),
 67→            message: "must have at least one criterion".into(),
 68→        });
 69→    } else {
 70→        let mut seen = HashSet::new();
 71→        for (i, criterion) in spec.criteria.iter().enumerate() {
 72→            if criterion.name.trim().is_empty() {
 73→                errors.push(SpecError {
 74→                    field: format!("criteria[{i}].name"),
 75→                    message: "required, must not be empty".into(),
 76→                });
 77→            } else if !seen.insert(&criterion.name) {
 78→                errors.push(SpecError {
 79→                    field: format!("criteria[{i}].name"),
 80→                    message: format!("duplicate criterion name `{}`", criterion.name),
 81→                });
 82→            }
 83→        }
 84→    }
 85→
 86→    if errors.is_empty() {
 87→        Ok(())
 88→    } else {
 89→        Err(errors)
 90→    }
 91→}
 92→
 93→/// Load and validate a spec from a file path.
 94→///
 95→/// Reads the file, parses it as TOML, and validates the result. Wraps
 96→/// parse errors in [`AssayError::SpecParse`] (with file path) and
 97→/// validation errors in [`AssayError::SpecValidation`].
 98→pub fn load(path: &Path) -> Result<Spec> {
 99→    let content = std::fs::read_to_string(path).map_err(|source| AssayError::Io {
100→        operation: "reading spec".into(),
101→        path: path.to_path_buf(),
102→        source,
103→    })?;
104→
105→    let spec: Spec = toml::from_str(&content).map_err(|e| AssayError::SpecParse {
106→        path: path.to_path_buf(),
107→        message: e.to_string(),
108→    })?;
109→
110→    if let Err(errors) = validate(&spec) {
111→        return Err(AssayError::SpecValidation {
112→            path: path.to_path_buf(),
113→            errors,
114→        });
115→    }
116→
117→    Ok(spec)
118→}
119→
120→/// Scan a directory for `.toml` spec files.
121→///
122→/// Performs a flat (non-recursive) scan. Non-`.toml` files are silently
123→/// skipped. Results are sorted by filename. After loading all valid specs,
124→/// duplicate `name` fields across files are detected and reported as errors.
125→pub fn scan(specs_dir: &Path) -> Result<ScanResult> {
126→    let entries = std::fs::read_dir(specs_dir).map_err(|source| AssayError::SpecScan {
127→        path: specs_dir.to_path_buf(),
128→        source,
129→    })?;
130→
131→    // Collect and sort directory entries by filename
132→    let mut entry_errors = Vec::new();
133→    let mut paths: Vec<_> = entries
134→        .filter_map(|entry| match entry {
135→            Ok(e) => Some(e.path()),
136→            Err(source) => {
137→                entry_errors.push(AssayError::Io {
138→                    operation: "reading directory entry".into(),
139→                    path: specs_dir.to_path_buf(),
140→                    source,
141→                });
142→                None
143→            }
144→        })
145→        .filter(|path| path.extension().is_some_and(|ext| ext == "toml"))
146→        .collect();
147→    paths.sort();
148→
149→    let mut specs = Vec::new();
150→    let mut errors = entry_errors;
151→
152→    for path in &paths {
153→        match load(path) {
154→            Ok(spec) => {
155→                let slug = match path.file_stem().and_then(|s| s.to_str()) {
156→                    Some(s) if !s.is_empty() => s.to_string(),
157→                    _ => {
158→                        errors.push(AssayError::Io {
159→                            operation: "extracting filename stem".into(),
160→                            path: path.clone(),
161→                            source: std::io::Error::new(
162→                                std::io::ErrorKind::InvalidData,
163→                                "file has no valid stem",
164→                            ),
165→                        });
166→                        continue;
167→                    }
168→                };
169→                specs.push((slug, spec));
170→            }
171→            Err(err) => {
172→                errors.push(err);
173→            }
174→        }
175→    }
176→
177→    // Detect duplicate spec names across files
178→    let mut seen_names: HashSet<String> = HashSet::new();
179→    let mut duplicate_indices = Vec::new();
180→    for (i, (_slug, spec)) in specs.iter().enumerate() {
181→        if !seen_names.insert(spec.name.clone()) {
182→            duplicate_indices.push(i);
183→        }
184→    }
185→
186→    // Remove duplicates in reverse order (to preserve indices) and add to errors
187→    for i in duplicate_indices.into_iter().rev() {
188→        let (slug, spec) = specs.remove(i);
189→        let path = specs_dir.join(format!("{slug}.toml"));
190→        errors.push(AssayError::SpecValidation {
191→            path,
192→            errors: vec![SpecError {
193→                field: "name".into(),
194→                message: format!("duplicate spec name `{}`", spec.name),
195→            }],
196→        });
197→    }
198→
199→    Ok(ScanResult { specs, errors })
200→}
