  7→/// Unified error type for all Assay operations.
  8→///
  9→/// New variants are added as downstream phases consume them.
 10→/// The `#[non_exhaustive]` attribute ensures adding variants
 11→/// is not a breaking change.
 12→#[derive(Debug, Error)]
 13→#[non_exhaustive]
 14→pub enum AssayError {
 15→    /// An I/O operation failed.
 16→    #[error("{operation} at `{path}`: {source}")]
 17→    Io {
 18→        /// What was being attempted (e.g., "reading config", "writing spec").
 19→        operation: String,
 20→        /// The file path involved.
 21→        path: PathBuf,
 22→        /// The underlying I/O error.
 23→        source: std::io::Error,
 24→    },
 25→
 26→    /// Config file parsing failed (invalid TOML or schema mismatch).
 27→    #[error("parsing config `{path}`: {message}")]
 28→    ConfigParse {
 29→        /// The config file that failed to parse.
 30→        path: PathBuf,
 31→        /// The parse error message (includes line/column from toml crate).
 32→        message: String,
 33→    },
 34→
 35→    /// Config validation failed (structurally valid TOML but semantically invalid).
 36→    #[error("invalid config `{path}`:\n{}", .errors.iter().map(|e| format!("  - {e}")).collect::<Vec<_>>().join("\n"))]
 37→    ConfigValidation {
 38→        /// The config file that failed validation.
 39→        path: PathBuf,
 40→        /// All validation errors found.
 41→        errors: Vec<ConfigError>,
 42→    },
 43→
 44→    /// Init refused because `.assay/` already exists.
 45→    #[error(".assay/ already exists. Remove it first to reinitialize.")]
 46→    AlreadyInitialized,
 47→
 48→    /// Spec file parsing failed (invalid TOML or schema mismatch).
 49→    #[error("parsing spec `{path}`: {message}")]
 50→    SpecParse {
 51→        /// The spec file that failed to parse.
 52→        path: PathBuf,
 53→        /// The parse error message (includes line/column from toml crate).
 54→        message: String,
 55→    },
 56→
 57→    /// Spec validation failed (structurally valid TOML but semantically invalid).
 58→    #[error("invalid spec `{path}`:\n{}", .errors.iter().map(|e| format!("  - {e}")).collect::<Vec<_>>().join("\n"))]
 59→    SpecValidation {
 60→        /// The spec file that failed validation.
 61→        path: PathBuf,
 62→        /// All validation errors found.
 63→        errors: Vec<SpecError>,
 64→    },
 65→
 66→    /// Spec directory scanning failed (I/O error reading the directory).
 67→    #[error("scanning specs directory `{path}`: {source}")]
 68→    SpecScan {
 69→        /// The directory that couldn't be scanned.
 70→        path: PathBuf,
 71→        /// The underlying I/O error.
 72→        source: std::io::Error,
 73→    },
 74→
 75→    /// A gate command failed to start (spawn error).
 76→    #[error("gate execution failed for `{cmd}` in `{working_dir}`: {source}")]
 77→    GateExecution {
 78→        /// The command that failed to spawn.
 79→        cmd: String,
 80→        /// The working directory where execution was attempted.
 81→        working_dir: PathBuf,
 82→        /// The underlying I/O error.
 83→        source: std::io::Error,
 84→    },
 85→
 86→    /// A spec was not found by name in the specs directory.
 87→    #[error("spec `{name}` not found in {specs_dir}")]
 88→    SpecNotFound {
 89→        /// The spec name that was looked up.
 90→        name: String,
 91→        /// The directory that was searched.
 92→        specs_dir: String,
 93→    },
 94→}
 95→
