  1→//! Gate types for defining quality checks and capturing their results.
  2→
  3→use chrono::{DateTime, Utc};
  4→use schemars::JsonSchema;
  5→use serde::{Deserialize, Serialize};
  6→
  7→/// The kind of gate to evaluate.
  8→///
  9→/// Uses internal tagging (`#[serde(tag = "kind")]`) so TOML output includes
 10→/// a `kind = "Command"` or `kind = "AlwaysPass"` discriminator field.
 11→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize, JsonSchema)]
 12→#[serde(tag = "kind")]
 13→pub enum GateKind {
 14→    /// A gate that runs a shell command and checks its exit code.
 15→    Command {
 16→        /// The shell command to execute.
 17→        cmd: String,
 18→    },
 19→
 20→    /// A gate that always passes — useful for placeholder or manual gates.
 21→    AlwaysPass,
 22→
 23→    /// A gate that checks whether a file exists at the given path.
 24→    FileExists {
 25→        /// Path to check, relative to the working directory.
 26→        path: String,
 27→    },
 28→}
 29→
 30→inventory::submit! {
 31→    crate::schema_registry::SchemaEntry {
 32→        name: "gate-kind",
 33→        generate: || schemars::schema_for!(GateKind),
 34→    }
 35→}
 36→
 37→/// The result of evaluating a gate.
 38→///
 39→/// Captures whether the gate passed, the command output (if any), timing,
 40→/// and which kind of gate produced this result (self-describing via `kind`).
 41→#[derive(Debug, Clone, Serialize, Deserialize, JsonSchema)]
 42→pub struct GateResult {
 43→    /// Whether the gate passed.
 44→    pub passed: bool,
 45→
 46→    /// Which gate kind produced this result.
 47→    pub kind: GateKind,
 48→
 49→    /// Standard output captured from the gate command.
 50→    /// Omitted from serialized output when empty.
 51→    #[serde(skip_serializing_if = "String::is_empty", default)]
 52→    pub stdout: String,
 53→
 54→    /// Standard error captured from the gate command.
 55→    /// Omitted from serialized output when empty.
 56→    #[serde(skip_serializing_if = "String::is_empty", default)]
 57→    pub stderr: String,
 58→
 59→    /// Exit code from the gate command, if applicable.
 60→    /// Omitted from serialized output when `None` (e.g., for `AlwaysPass` gates).
 61→    #[serde(skip_serializing_if = "Option::is_none", default)]
 62→    pub exit_code: Option<i32>,
 63→
 64→    /// How long the gate took to evaluate, in milliseconds.
 65→    pub duration_ms: u64,
 66→
 67→    /// When the gate evaluation completed.
 68→    pub timestamp: DateTime<Utc>,
 69→
 70→    /// Whether stdout or stderr was truncated due to size limits.
 71→    /// Omitted from serialized output when false.
 72→    #[serde(default, skip_serializing_if = "std::ops::Not::not")]
 73→    pub truncated: bool,
 74→
 75→    /// Original byte count before truncation.
 76→    /// Omitted from serialized output when `None`.
 77→    #[serde(skip_serializing_if = "Option::is_none", default)]
 78→    pub original_bytes: Option<u64>,
 79→}
 80→
