  1→use clap::{Parser, Subcommand};
  2→
  3→#[derive(Parser)]
  4→#[command(
  5→    name = "assay",
  6→    version,
  7→    about = "Agentic development kit with spec-driven workflows"
  8→)]
  9→struct Cli {
 10→    #[command(subcommand)]
 11→    command: Option<Command>,
 12→}
 13→
 14→#[derive(Subcommand)]
 15→enum Command {
 16→    /// Initialize a new Assay project in the current directory
 17→    Init {
 18→        /// Override the inferred project name
 19→        #[arg(long)]
 20→        name: Option<String>,
 21→    },
 22→    /// MCP server operations
 23→    Mcp {
 24→        #[command(subcommand)]
 25→        command: McpCommand,
 26→    },
 27→    /// Manage spec files
 28→    Spec {
 29→        #[command(subcommand)]
 30→        command: SpecCommand,
 31→    },
 32→}
 33→
 34→#[derive(Subcommand)]
 35→enum McpCommand {
 36→    /// Start the MCP server (stdio transport)
 37→    Serve,
 38→}
 39→
 40→#[derive(Subcommand)]
 41→enum SpecCommand {
 42→    /// Display a spec's criteria in detail
 43→    Show {
 44→        /// Spec name (filename without .toml extension)
 45→        name: String,
 46→        /// Output as JSON instead of table
 47→        #[arg(long)]
 48→        json: bool,
 49→    },
 50→    /// List all available specs
 51→    List,
 52→}
 53→
 54→/// Check whether terminal colors should be used.
 55→///
 56→/// Returns `false` when the `NO_COLOR` environment variable is set
 57→/// (any value, including empty — per <https://no-color.org/>).
 58→fn colors_enabled() -> bool {
 59→    std::env::var("NO_COLOR").is_err()
 60→}
 61→
 62→/// Format a criterion type label, optionally with ANSI color.
 63→///
 64→/// "executable" (has a `cmd`) renders green; "descriptive" renders yellow.
 65→fn format_criteria_type(has_cmd: bool, color: bool) -> String {
 66→    if has_cmd {
 67→        if color {
 68→            "\x1b[32mexecutable\x1b[0m".to_string()
 69→        } else {
 70→            "executable".to_string()
 71→        }
 72→    } else if color {
 73→        "\x1b[33mdescriptive\x1b[0m".to_string()
 74→    } else {
 75→        "descriptive".to_string()
 76→    }
 77→}
 78→
 79→/// Resolve the project root directory, exiting on failure.
 80→fn project_root() -> std::path::PathBuf {
 81→    std::env::current_dir().unwrap_or_else(|e| {
 82→        eprintln!("Error: could not determine current directory: {e}");
 83→        std::process::exit(1);
 84→    })
 85→}
 86→
 87→/// Handle `assay spec show <name> [--json]`.
 88→fn handle_spec_show(name: &str, json: bool) {
 89→    let root = project_root();
 90→    let config = match assay_core::config::load(&root) {
 91→        Ok(c) => c,
 92→        Err(e) => {
 93→            eprintln!("Error: {e}");
 94→            std::process::exit(1);
 95→        }
 96→    };
 97→    let specs_dir = root.join(".assay").join(&config.specs_dir);
 98→    let spec_path = specs_dir.join(format!("{name}.toml"));
 99→
100→    let spec = match assay_core::spec::load(&spec_path) {
101→        Ok(s) => s,
102→        Err(assay_core::AssayError::Io { source, .. })
103→            if source.kind() == std::io::ErrorKind::NotFound =>
104→        {
105→            eprintln!("Error: spec '{name}' not found in {}", config.specs_dir);
106→            std::process::exit(1);
107→        }
108→        Err(e) => {
109→            eprintln!("Error: {e}");
110→            std::process::exit(1);
111→        }
112→    };
113→
114→    if json {
115→        let output = serde_json::to_string_pretty(&spec).unwrap_or_else(|e| {
116→            eprintln!("Error: failed to serialize spec: {e}");
117→            std::process::exit(1);
118→        });
119→        println!("{output}");
120→        return;
121→    }
122→
123→    // Table output
124→    let color = colors_enabled();
125→
126→    println!("Spec: {}", spec.name);
127→    if !spec.description.is_empty() {
128→        println!("Description: {}", spec.description);
129→    }
130→    println!();
131→
132→    // Column widths: compute from data
133→    let num_width = spec.criteria.len().to_string().len().max(1);
134→    let name_width = spec
135→        .criteria
136→        .iter()
137→        .map(|c| c.name.len())
138→        .max()
139→        .unwrap_or(9)
140→        .max(9); // "Criterion" header
141→    let type_width = 11; // "descriptive" is longest at 11
142→
143→    // Header
144→    println!(
145→        "  {:<num_w$}  {:<name_w$}  {:<type_w$}  Command",
146→        "#",
147→        "Criterion",
148→        "Type",
149→        num_w = num_width,
150→        name_w = name_width,
151→        type_w = type_width,
152→    );
153→    // Separator
154→    println!(
155→        "  {:<num_w$}  {:<name_w$}  {:<type_w$}  {}",
156→        "\u{2500}".repeat(num_width),
157→        "\u{2500}".repeat(name_width),
158→        "\u{2500}".repeat(type_width),
159→        "\u{2500}".repeat(7),
160→        num_w = num_width,
161→        name_w = name_width,
162→        type_w = type_width,
163→    );
164→
165→    for (i, criterion) in spec.criteria.iter().enumerate() {
166→        let type_label = format_criteria_type(criterion.cmd.is_some(), color);
167→        let cmd_display = criterion.cmd.as_deref().unwrap_or("");
168→
169→        // When color is enabled the ANSI codes add non-printing characters,
170→        // so we need to pad the plain text width manually.
171→        if color {
172→            println!(
173→                "  {:<num_w$}  {:<name_w$}  {:<type_w$}  {cmd_display}",
174→                i + 1,
175→                criterion.name,
176→                type_label,
177→                num_w = num_width,
178→                name_w = name_width,
179→                // ANSI codes add 9 chars (\x1b[32m = 5 + \x1b[0m = 4) that don't display
180→                type_w = type_width + 9,
181→            );
182→        } else {
183→            println!(
184→                "  {:<num_w$}  {:<name_w$}  {:<type_w$}  {cmd_display}",
185→                i + 1,
186→                criterion.name,
187→                type_label,
188→                num_w = num_width,
189→                name_w = name_width,
190→                type_w = type_width,
191→            );
192→        }
193→    }
194→}
195→
196→/// Handle `assay spec list`.
197→fn handle_spec_list() {
198→    let root = project_root();
199→    let config = match assay_core::config::load(&root) {
200→        Ok(c) => c,
201→        Err(e) => {
202→            eprintln!("Error: {e}");
