  1→use clap::{Parser, Subcommand};
  2→
  3→#[derive(Parser)]
  4→#[command(
  5→    name = "assay",
  6→    version,
  7→    about = "Agentic development kit with spec-driven workflows"
  8→)]
  9→struct Cli {
 10→    #[command(subcommand)]
 11→    command: Option<Command>,
 12→}
 13→
 14→#[derive(Subcommand)]
 15→enum Command {
 16→    /// Initialize a new Assay project in the current directory
 17→    Init {
 18→        /// Override the inferred project name
 19→        #[arg(long)]
 20→        name: Option<String>,
 21→    },
 22→    /// MCP server operations
 23→    Mcp {
 24→        #[command(subcommand)]
 25→        command: McpCommand,
 26→    },
 27→    /// Manage spec files
 28→    Spec {
 29→        #[command(subcommand)]
 30→        command: SpecCommand,
 31→    },
 32→    /// Run quality gates for a spec
 33→    Gate {
 34→        #[command(subcommand)]
 35→        command: GateCommand,
 36→    },
 37→}
 38→
 39→#[derive(Subcommand)]
 40→enum McpCommand {
 41→    /// Start the MCP server (stdio transport)
 42→    Serve,
 43→}
 44→
 45→#[derive(Subcommand)]
 46→enum SpecCommand {
 47→    /// Display a spec's criteria in detail
 48→    Show {
 49→        /// Spec name (filename without .toml extension)
 50→        name: String,
 51→        /// Output as JSON instead of table
 52→        #[arg(long)]
 53→        json: bool,
 54→    },
 55→    /// List all available specs
 56→    List,
 57→}
 58→
 59→#[derive(Subcommand)]
 60→enum GateCommand {
 61→    /// Run all executable criteria for a spec
 62→    Run {
 63→        /// Spec name (filename without .toml extension)
 64→        name: String,
 65→        /// Override timeout for all criteria (seconds)
 66→        #[arg(long)]
 67→        timeout: Option<u64>,
 68→        /// Show evidence for all criteria, not just failures
 69→        #[arg(short, long)]
 70→        verbose: bool,
 71→        /// Output as JSON instead of streaming display
 72→        #[arg(long)]
 73→        json: bool,
 74→    },
 75→}
 76→
 77→/// Check whether terminal colors should be used.
 78→///
 79→/// Returns `false` when the `NO_COLOR` environment variable is set
 80→/// (any value, including empty — per <https://no-color.org/>).
 81→fn colors_enabled() -> bool {
 82→    std::env::var("NO_COLOR").is_err()
 83→}
 84→
 85→/// Format a criterion type label, optionally with ANSI color.
 86→///
 87→/// "executable" (has a `cmd`) renders green; "descriptive" renders yellow.
 88→fn format_criteria_type(has_cmd: bool, color: bool) -> String {
 89→    if has_cmd {
 90→        if color {
 91→            "\x1b[32mexecutable\x1b[0m".to_string()
 92→        } else {
 93→            "executable".to_string()
 94→        }
 95→    } else if color {
 96→        "\x1b[33mdescriptive\x1b[0m".to_string()
 97→    } else {
 98→        "descriptive".to_string()
 99→    }
100→}
101→
102→/// Format "ok" with optional green color.
103→fn format_pass(color: bool) -> &'static str {
104→    if color { "\x1b[32mok\x1b[0m" } else { "ok" }
105→}
106→
107→/// Format "FAILED" with optional red color.
108→fn format_fail(color: bool) -> &'static str {
109→    if color {
110→        "\x1b[31mFAILED\x1b[0m"
111→    } else {
112→        "FAILED"
113→    }
114→}
115→
116→/// Format a number with optional ANSI color, only applying color when
117→/// the value is non-zero.
118→fn format_count(value: usize, ansi_code: &str, color: bool) -> String {
119→    if color && value > 0 {
120→        format!("{ansi_code}{value}\x1b[0m")
121→    } else {
122→        value.to_string()
123→    }
124→}
125→
126→/// Resolve the project root directory, exiting on failure.
127→fn project_root() -> std::path::PathBuf {
128→    std::env::current_dir().unwrap_or_else(|e| {
129→        eprintln!("Error: could not determine current directory: {e}");
130→        std::process::exit(1);
131→    })
132→}
133→
134→/// Handle `assay spec show <name> [--json]`.
135→fn handle_spec_show(name: &str, json: bool) {
136→    let root = project_root();
137→    let config = match assay_core::config::load(&root) {
138→        Ok(c) => c,
139→        Err(e) => {
140→            eprintln!("Error: {e}");
141→            std::process::exit(1);
142→        }
143→    };
144→    let specs_dir = root.join(".assay").join(&config.specs_dir);
145→    let spec_path = specs_dir.join(format!("{name}.toml"));
146→
147→    let spec = match assay_core::spec::load(&spec_path) {
148→        Ok(s) => s,
149→        Err(assay_core::AssayError::Io { source, .. })
150→            if source.kind() == std::io::ErrorKind::NotFound =>
151→        {
152→            eprintln!("Error: spec '{name}' not found in {}", config.specs_dir);
153→            std::process::exit(1);
154→        }
155→        Err(e) => {
156→            eprintln!("Error: {e}");
157→            std::process::exit(1);
158→        }
159→    };
160→
161→    if json {
162→        let output = serde_json::to_string_pretty(&spec).unwrap_or_else(|e| {
163→            eprintln!("Error: failed to serialize spec: {e}");
164→            std::process::exit(1);
165→        });
166→        println!("{output}");
167→        return;
168→    }
169→
170→    // Table output
171→    let color = colors_enabled();
172→
173→    println!("Spec: {}", spec.name);
174→    if !spec.description.is_empty() {
175→        println!("Description: {}", spec.description);
176→    }
177→    println!();
178→
179→    // Column widths: compute from data
180→    let num_width = spec.criteria.len().to_string().len().max(1);
181→    let name_width = spec
182→        .criteria
183→        .iter()
184→        .map(|c| c.name.len())
185→        .max()
186→        .unwrap_or(9)
187→        .max(9); // "Criterion" header
188→    let type_width = 11; // "descriptive" is longest at 11
189→
190→    // Header
191→    println!(
192→        "  {:<num_w$}  {:<name_w$}  {:<type_w$}  Command",
193→        "#",
194→        "Criterion",
195→        "Type",
196→        num_w = num_width,
197→        name_w = name_width,
198→        type_w = type_width,
199→    );
200→    // Separator
201→    println!(
202→        "  {:<num_w$}  {:<name_w$}  {:<type_w$}  {}",
203→        "\u{2500}".repeat(num_width),
204→        "\u{2500}".repeat(name_width),
205→        "\u{2500}".repeat(type_width),
206→        "\u{2500}".repeat(7),
207→        num_w = num_width,
208→        name_w = name_width,
209→        type_w = type_width,
210→    );
211→
212→    for (i, criterion) in spec.criteria.iter().enumerate() {
213→        let type_label = format_criteria_type(criterion.cmd.is_some(), color);
214→        let cmd_display = criterion.cmd.as_deref().unwrap_or("");
215→
216→        // When color is enabled the ANSI codes add non-printing characters,
217→        // so we need to pad the plain text width manually.
218→        if color {
219→            println!(
220→                "  {:<num_w$}  {:<name_w$}  {:<type_w$}  {cmd_display}",
221→                i + 1,
222→                criterion.name,
223→                type_label,
224→                num_w = num_width,
225→                name_w = name_width,
226→                // ANSI codes add 9 chars (\x1b[32m = 5 + \x1b[0m = 4) that don't display
227→                type_w = type_width + 9,
228→            );
229→        } else {
230→            println!(
231→                "  {:<num_w$}  {:<name_w$}  {:<type_w$}  {cmd_display}",
232→                i + 1,
233→                criterion.name,
234→                type_label,
235→                num_w = num_width,
236→                name_w = name_width,
237→                type_w = type_width,
238→            );
239→        }
240→    }
241→}
242→
243→/// Handle `assay spec list`.
244→fn handle_spec_list() {
245→    let root = project_root();
246→    let config = match assay_core::config::load(&root) {
247→        Ok(c) => c,
248→        Err(e) => {
249→            eprintln!("Error: {e}");
250→            std::process::exit(1);
251→        }
252→    };
253→    let specs_dir = root.join(".assay").join(&config.specs_dir);
254→
255→    let result = match assay_core::spec::scan(&specs_dir) {
256→        Ok(r) => r,
257→        Err(e) => {
258→            eprintln!("Error: {e}");
259→            std::process::exit(1);
260→        }
261→    };
262→
263→    // Print warnings for scan errors
264→    for err in &result.errors {
265→        eprintln!("Warning: {err}");
266→    }
267→
268→    if result.specs.is_empty() {
269→        println!("No specs found in {}", config.specs_dir);
270→        return;
271→    }
272→
273→    // Compute name column width for alignment
274→    let name_width = result
275→        .specs
276→        .iter()
277→        .map(|(slug, _)| slug.len())
278→        .max()
279→        .unwrap_or(0);
280→
281→    println!("Specs:");
282→    for (slug, spec) in &result.specs {
283→        if spec.description.is_empty() {
284→            println!("  {slug}");
285→        } else {
286→            println!(
287→                "  {:<width$}  {}",
288→                slug,
289→                spec.description,
290→                width = name_width
291→            );
292→        }
293→    }
294→}
295→
296→/// Handle `assay gate run <name> [--timeout N] [--verbose] [--json]`.
297→fn handle_gate_run(name: &str, cli_timeout: Option<u64>, verbose: bool, json: bool) {
298→    let root = project_root();
299→    let config = match assay_core::config::load(&root) {
300→        Ok(c) => c,
301→        Err(e) => {
302→            eprintln!("Error: {e}");
303→            std::process::exit(1);
304→        }
305→    };
306→    let specs_dir = root.join(".assay").join(&config.specs_dir);
307→    let spec_path = specs_dir.join(format!("{name}.toml"));
308→
309→    let spec = match assay_core::spec::load(&spec_path) {
310→        Ok(s) => s,
311→        Err(assay_core::AssayError::Io { source, .. })
312→            if source.kind() == std::io::ErrorKind::NotFound =>
313→        {
314→            eprintln!("Error: spec '{name}' not found in {}", config.specs_dir);
315→            std::process::exit(1);
316→        }
317→        Err(e) => {
318→            eprintln!("Error: {e}");
319→            std::process::exit(1);
320→        }
321→    };
322→
323→    // Resolve working directory: config gates.working_dir > project root
324→    let working_dir = match config.gates.as_ref().and_then(|g| g.working_dir.as_deref()) {
325→        Some(dir) => {
326→            let path = std::path::Path::new(dir);
327→            if path.is_absolute() {
328→                path.to_path_buf()
329→            } else {
330→                root.join(path)
331→            }
332→        }
333→        None => root.clone(),
334→    };
335→
336→    // Extract config timeout
337→    let config_timeout = config.gates.as_ref().map(|g| g.default_timeout);
338→
339→    // JSON output path: evaluate all at once, serialize, print
340→    if json {
341→        let summary =
342→            assay_core::gate::evaluate_all(&spec, &working_dir, cli_timeout, config_timeout);
343→        let output = serde_json::to_string_pretty(&summary).unwrap_or_else(|e| {
344→            eprintln!("Error: failed to serialize gate results: {e}");
345→            std::process::exit(1);
346→        });
347→        println!("{output}");
348→        if summary.failed > 0 {
349→            std::process::exit(1);
350→        }
351→        return;
352→    }
353→
354→    // Streaming display path: iterate criteria manually for live progress
355→    let color = colors_enabled();
356→
357→    let mut passed = 0usize;
358→    let mut failed = 0usize;
359→    let mut skipped = 0usize;
360→    let executable_count = spec.criteria.iter().filter(|c| c.cmd.is_some()).count();
361→
362→    if executable_count == 0 {
363→        println!("No executable criteria found");
364→        return;
365→    }
366→
367→    for criterion in &spec.criteria {
368→        // Descriptive-only criteria: skip silently during streaming
369→        if criterion.cmd.is_none() {
370→            skipped += 1;
371→            continue;
372→        }
373→
374→        // Show "running" state (overwritable line on stderr)
375→        if color {
376→            eprint!("\r\x1b[K  {} ... running", criterion.name);
377→        } else {
378→            eprint!("\r  {} ... running", criterion.name);
379→        }
380→
381→        let timeout =
382→            assay_core::gate::resolve_timeout(cli_timeout, criterion.timeout, config_timeout);
383→
384→        match assay_core::gate::evaluate(criterion, &working_dir, timeout) {
385→            Ok(result) => {
386→                let status_label = if result.passed {
387→                    passed += 1;
388→                    format_pass(color)
389→                } else {
390→                    failed += 1;
391→                    format_fail(color)
392→                };
393→
394→                // Replace the running line with final status
395→                if color {
396→                    eprintln!("\r\x1b[K  {} ... {}", criterion.name, status_label);
397→                } else {
398→                    eprintln!("\r  {} ... {}", criterion.name, status_label);
399→                }
400→
401→                // Show evidence for failures (always) or all criteria (--verbose)
402→                if !result.passed || verbose {
403→                    print_evidence(&result.stdout, &result.stderr, result.truncated, color);
404→                }
405→            }
406→            Err(err) => {
407→                failed += 1;
408→
409→                // Replace the running line with FAILED
410→                if color {
411→                    eprintln!("\r\x1b[K  {} ... {}", criterion.name, format_fail(color));
412→                } else {
413→                    eprintln!("\r  {} ... {}", criterion.name, format_fail(color));
414→                }
415→                eprintln!("    error: {err}");
416→            }
417→        }
418→    }
419→
420→    // Summary line (stdout for capturability)
421→    let total = passed + failed + skipped;
422→    let passed_str = format_count(passed, "\x1b[32m", color);
423→    let failed_str = format_count(failed, "\x1b[31m", color);
424→    let skipped_str = format_count(skipped, "\x1b[33m", color);
425→
426→    println!();
427→    println!(
428→        "Results: {passed_str} passed, {failed_str} failed, {skipped_str} skipped (of {total} total)"
429→    );
430→
431→    if failed > 0 {
432→        std::process::exit(1);
433→    }
434→}
435→
436→/// Print evidence (stdout/stderr) for a gate result.
437→///
438→/// Multi-line output is indented with 4 spaces per line. If the output
439→/// was truncated, a note is appended.
440→fn print_evidence(stdout: &str, stderr: &str, truncated: bool, color: bool) {
441→    let stdout = stdout.trim();
442→    let stderr = stderr.trim();
443→
444→    if !stdout.is_empty() {
445→        eprintln!("    stdout:");
446→        for line in stdout.lines() {
447→            eprintln!("      {line}");
448→        }
449→    }
450→    if !stderr.is_empty() {
451→        eprintln!("    stderr:");
452→        for line in stderr.lines() {
453→            eprintln!("      {line}");
454→        }
455→    }
456→    if truncated {
457→        let note = if color {
458→            "\x1b[33m[output truncated]\x1b[0m"
459→        } else {
460→            "[output truncated]"
461→        };
462→        eprintln!("    {note}");
463→    }
464→}
465→
466→/// Initialize tracing to stderr for MCP server operation.
467→///
468→/// Default level is `warn`. Override via `RUST_LOG` environment variable.
469→/// Stdout is reserved for JSON-RPC — all diagnostics go to stderr.
470→fn init_mcp_tracing() {
471→    use tracing_subscriber::EnvFilter;
472→
473→    let filter = EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("warn"));
474→
475→    if let Err(e) = tracing_subscriber::fmt()
476→        .with_env_filter(filter)
477→        .with_writer(std::io::stderr)
478→        .with_ansi(false)
479→        .try_init()
480→    {
481→        eprintln!("[assay] warning: failed to initialize tracing: {e}");
482→    }
483→}
484→
485→#[tokio::main]
486→async fn main() {
487→    let cli = Cli::parse();
488→
489→    match cli.command {
490→        Some(Command::Init { name }) => {
491→            let root = std::env::current_dir().unwrap_or_else(|e| {
492→                eprintln!("Error: could not determine current directory: {e}");
493→                std::process::exit(1);
494→            });
495→            let options = assay_core::init::InitOptions { name };
496→            match assay_core::init::init(&root, &options) {
497→                Ok(result) => {
498→                    println!("  Created assay project `{}`", result.project_name);
499→                    for path in &result.created_files {
500→                        let display = path.strip_prefix(&root).unwrap_or(path);
501→                        println!("    created {}", display.display());
502→                    }
503→                }
504→                Err(e) => {
505→                    eprintln!("Error: {e}");
506→                    std::process::exit(1);
507→                }
508→            }
509→        }
510→        Some(Command::Mcp { command }) => match command {
511→            McpCommand::Serve => {
512→                init_mcp_tracing();
513→                if let Err(e) = assay_mcp::serve().await {
514→                    eprintln!("Error: {e:?}");
515→                    std::process::exit(1);
516→                }
517→            }
518→        },
519→        Some(Command::Spec { command }) => match command {
520→            SpecCommand::Show { name, json } => handle_spec_show(&name, json),
521→            SpecCommand::List => handle_spec_list(),
522→        },
523→        Some(Command::Gate { command }) => match command {
524→            GateCommand::Run {
525→                name,
526→                timeout,
527→                verbose,
528→                json,
529→            } => {
530→                handle_gate_run(&name, timeout, verbose, json);
531→            }
532→        },
533→        None => {
534→            println!("assay {}", env!("CARGO_PKG_VERSION"));
535→        }
536→    }
537→}
