  1→//! Quality gate evaluation.
  2→//!
  3→//! Gates are checkpoints that verify work meets quality criteria
  4→//! before allowing progression through the workflow. This module
  5→//! provides synchronous gate evaluation — command execution with
  6→//! timeout enforcement, file existence checks, and aggregate result
  7→//! summaries.
  8→//!
  9→//! # Async Usage
 10→//!
 11→//! All functions in this module are synchronous. When calling from an
 12→//! async context (e.g., MCP server handlers), wrap calls with
 13→//! [`tokio::task::spawn_blocking`]:
 14→//!
 15→//! ```ignore
 16→//! let result = tokio::task::spawn_blocking(move || {
 17→//!     gate::evaluate(&criterion, &working_dir, timeout)
 18→//! }).await??;
 19→//! ```
 20→
 21→use std::path::Path;
 22→use std::process::{Command, Stdio};
 23→use std::time::{Duration, Instant};
 24→
 25→use chrono::Utc;
 26→use serde::Serialize;
 27→
 28→use assay_types::{Criterion, GateKind, GateResult, Spec};
 29→
 30→use crate::error::{AssayError, Result};
 31→
 32→/// Maximum bytes to retain from stdout/stderr capture (64 KB).
 33→const MAX_OUTPUT_BYTES: usize = 65_536;
 34→
 35→/// Polling interval for `try_wait` timeout loop.
 36→const POLL_INTERVAL_MS: u64 = 50;
 37→
 38→/// Minimum timeout floor in seconds.
 39→const MIN_TIMEOUT_SECS: u64 = 1;
 40→
 41→/// Summary of evaluating all criteria in a spec.
 42→///
 43→/// This is a computed summary type (not a persisted DTO). It lives in
 44→/// `assay-core`, not `assay-types`, because it represents aggregate
 45→/// evaluation results rather than configuration or state.
 46→#[derive(Debug, Clone, Serialize)]
 47→pub struct GateRunSummary {
 48→    /// Spec name that was evaluated.
 49→    pub spec_name: String,
 50→    /// Results for each criterion that was evaluated or skipped.
 51→    pub results: Vec<CriterionResult>,
 52→    /// Number of criteria that passed.
 53→    pub passed: usize,
 54→    /// Number of criteria that failed.
 55→    pub failed: usize,
 56→    /// Number of criteria skipped (descriptive-only, no cmd).
 57→    pub skipped: usize,
 58→    /// Total wall-clock duration for all evaluations in milliseconds.
 59→    pub total_duration_ms: u64,
 60→}
 61→
 62→/// A criterion paired with its evaluation result.
 63→#[derive(Debug, Clone, Serialize)]
 64→pub struct CriterionResult {
 65→    /// The name of the criterion that was evaluated.
 66→    pub criterion_name: String,
 67→    /// The gate result, or `None` if skipped (no cmd).
 68→    pub result: Option<GateResult>,
 69→}
 70→
 71→/// Evaluate a single criterion as a gate.
 72→///
 73→/// Derives `GateKind` from criterion fields: if `cmd` is `Some`, it's
 74→/// `GateKind::Command`; if `cmd` is `None`, it's `GateKind::AlwaysPass`.
 75→///
 76→/// `working_dir` is required — this function never inherits the process CWD.
 77→/// `timeout` is the maximum wall-clock time for the command to complete.
 78→///
 79→/// # Async Usage
 80→///
 81→/// This function is synchronous. From async code, use:
 82→/// ```ignore
 83→/// tokio::task::spawn_blocking(move || gate::evaluate(&criterion, &dir, timeout)).await?
 84→/// ```
 85→pub fn evaluate(
 86→    criterion: &Criterion,
 87→    working_dir: &Path,
 88→    timeout: Duration,
 89→) -> Result<GateResult> {
 90→    match &criterion.cmd {
 91→        Some(cmd) => evaluate_command(cmd, working_dir, timeout),
 92→        None => evaluate_always_pass(),
 93→    }
 94→}
 95→
 96→/// Evaluate all criteria in a spec sequentially.
 97→///
 98→/// Skips criteria without `cmd` (records as skipped in summary). Uses
 99→/// [`resolve_timeout`] for each criterion's timeout. Individual criterion
100→/// failures are captured in `GateResult`, not propagated as errors. If
101→/// [`evaluate`] returns an `Err` (spawn failure), it's captured as a
102→/// failed `CriterionResult` with error details in stderr.
103→///
104→/// # Async Usage
105→///
106→/// This function is synchronous. From async code, use:
107→/// ```ignore
108→/// tokio::task::spawn_blocking(move || {
109→///     gate::evaluate_all(&spec, &dir, cli_timeout, config_timeout)
110→/// }).await?
111→/// ```
112→pub fn evaluate_all(
113→    spec: &Spec,
114→    working_dir: &Path,
115→    cli_timeout: Option<u64>,
116→    config_timeout: Option<u64>,
117→) -> GateRunSummary {
118→    let start = Instant::now();
119→    let mut results = Vec::with_capacity(spec.criteria.len());
120→    let mut passed = 0usize;
121→    let mut failed = 0usize;
122→    let mut skipped = 0usize;
123→
124→    for criterion in &spec.criteria {
125→        if criterion.cmd.is_none() {
126→            skipped += 1;
127→            results.push(CriterionResult {
128→                criterion_name: criterion.name.clone(),
129→                result: None,
130→            });
131→            continue;
132→        }
133→
134→        let timeout = resolve_timeout(cli_timeout, criterion.timeout, config_timeout);
135→
136→        match evaluate(criterion, working_dir, timeout) {
137→            Ok(gate_result) => {
138→                if gate_result.passed {
139→                    passed += 1;
140→                } else {
141→                    failed += 1;
142→                }
143→                results.push(CriterionResult {
144→                    criterion_name: criterion.name.clone(),
145→                    result: Some(gate_result),
146→                });
147→            }
148→            Err(err) => {
149→                failed += 1;
150→                results.push(CriterionResult {
151→                    criterion_name: criterion.name.clone(),
152→                    result: Some(GateResult {
153→                        passed: false,
154→                        kind: GateKind::Command {
155→                            cmd: criterion.cmd.clone().unwrap_or_default(),
156→                        },
157→                        stdout: String::new(),
158→                        stderr: format!("gate evaluation error: {err}"),
159→                        exit_code: None,
160→                        duration_ms: 0,
161→                        timestamp: Utc::now(),
162→                        truncated: false,
163→                        original_bytes: None,
164→                    }),
165→                });
166→            }
167→        }
168→    }
169→
170→    GateRunSummary {
171→        spec_name: spec.name.clone(),
172→        results,
173→        passed,
174→        failed,
175→        skipped,
176→        total_duration_ms: start.elapsed().as_millis() as u64,
177→    }
178→}
179→
180→/// Resolve the effective timeout from three tiers of configuration.
181→///
182→/// Precedence: CLI `--timeout` > per-criterion `timeout` > config global > 300s default.
183→/// Enforces a minimum floor of 1 second.
184→pub fn resolve_timeout(
185→    cli_timeout: Option<u64>,
186→    criterion_timeout: Option<u64>,
187→    config_timeout: Option<u64>,
188→) -> Duration {
189→    let seconds = cli_timeout
190→        .or(criterion_timeout)
191→        .or(config_timeout)
192→        .unwrap_or(300);
193→    Duration::from_secs(seconds.max(MIN_TIMEOUT_SECS))
194→}
195→
196→/// Evaluate a file existence gate.
197→///
198→/// Resolves `path` relative to `working_dir` and checks whether the
199→/// file exists. No process execution, no timeout needed.
200→pub fn evaluate_file_exists(path: &str, working_dir: &Path) -> Result<GateResult> {
201→    let start = Instant::now();
202→    let full_path = working_dir.join(path);
203→    let exists = full_path.exists();
204→
205→    Ok(GateResult {
206→        passed: exists,
207→        kind: GateKind::FileExists {
208→            path: path.to_string(),
209→        },
210→        stdout: String::new(),
211→        stderr: if exists {
212→            String::new()
213→        } else {
214→            format!("file not found: {}", full_path.display())
215→        },
216→        exit_code: None,
217→        duration_ms: start.elapsed().as_millis() as u64,
218→        timestamp: Utc::now(),
219→        truncated: false,
220→        original_bytes: None,
221→    })
222→}
223→
224→/// Execute a shell command and capture its result.
225→///
226→/// Spawns `sh -c <cmd>` with piped stdout/stderr, uses reader threads
227→/// for deadlock-free pipe draining, and polls `try_wait` for timeout
228→/// enforcement. On timeout, kills the process group (Unix) and reaps
229→/// the zombie.
230→fn evaluate_command(cmd: &str, working_dir: &Path, timeout: Duration) -> Result<GateResult> {
231→    let start = Instant::now();
232→
233→    let mut command = Command::new("sh");
234→    command
235→        .args(["-c", cmd])
236→        .current_dir(working_dir)
237→        .stdout(Stdio::piped())
238→        .stderr(Stdio::piped());
239→
240→    // On Unix, put child in its own process group so timeout kills the tree
241→    #[cfg(unix)]
242→    {
243→        use std::os::unix::process::CommandExt;
244→        command.process_group(0);
245→    }
246→
247→    let mut child = command
248→        .spawn()
249→        .map_err(|source| AssayError::GateExecution {
250→            cmd: cmd.to_string(),
251→            working_dir: working_dir.to_path_buf(),
252→            source,
253→        })?;
254→
255→    // Take pipe handles before waiting (avoids borrow issues)
256→    let stdout_handle = child.stdout.take();
257→    let stderr_handle = child.stderr.take();
258→
259→    // Spawn reader threads to drain pipes (prevents deadlock)
260→    let stdout_thread = std::thread::spawn(move || {
261→        let mut buf = Vec::new();
262→        if let Some(mut stdout) = stdout_handle {
263→            let _ = std::io::Read::read_to_end(&mut stdout, &mut buf);
264→        }
265→        buf
266→    });
267→    let stderr_thread = std::thread::spawn(move || {
268→        let mut buf = Vec::new();
269→        if let Some(mut stderr) = stderr_handle {
270→            let _ = std::io::Read::read_to_end(&mut stderr, &mut buf);
271→        }
272→        buf
273→    });
274→
275→    // Poll for completion with timeout
276→    let status = loop {
277→        match child.try_wait() {
278→            Ok(Some(status)) => break Some(status),
279→            Ok(None) => {
280→                if start.elapsed() >= timeout {
281→                    let _ = child.kill();
282→                    let _ = child.wait(); // Reap zombie
283→                    break None;
284→                }
285→                std::thread::sleep(Duration::from_millis(POLL_INTERVAL_MS));
286→            }
287→            Err(e) => {
288→                return Err(AssayError::GateExecution {
289→                    cmd: cmd.to_string(),
290→                    working_dir: working_dir.to_path_buf(),
291→                    source: e,
292→                });
293→            }
294→        }
295→    };
296→
297→    let duration_ms = start.elapsed().as_millis() as u64;
298→
299→    // Join reader threads (safe: process is dead, pipes will EOF)
300→    let stdout_bytes = stdout_thread.join().unwrap_or_default();
301→    let stderr_bytes = stderr_thread.join().unwrap_or_default();
302→
303→    let stdout_raw = String::from_utf8_lossy(&stdout_bytes);
304→    let stderr_raw = String::from_utf8_lossy(&stderr_bytes);
305→
306→    // Track original sizes for truncation metadata
307→    let original_stdout_len = stdout_raw.len();
308→    let original_stderr_len = stderr_raw.len();
309→
310→    // Apply truncation (tail-biased)
311→    let (stdout_str, stdout_truncated) = truncate_output(&stdout_raw, MAX_OUTPUT_BYTES);
312→    let (stderr_str, stderr_truncated) = truncate_output(&stderr_raw, MAX_OUTPUT_BYTES);
313→
314→    let truncated = stdout_truncated || stderr_truncated;
315→    let original_bytes = if truncated {
316→        Some((original_stdout_len + original_stderr_len) as u64)
317→    } else {
318→        None
319→    };
320→
321→    // Build result based on whether timeout occurred
322→    match status {
323→        Some(exit_status) => {
324→            let exit_code = exit_status.code();
325→            Ok(GateResult {
326→                passed: exit_status.success(),
327→                kind: GateKind::Command {
328→                    cmd: cmd.to_string(),
329→                },
330→                stdout: stdout_str,
331→                stderr: stderr_str,
332→                exit_code,
333→                duration_ms,
334→                timestamp: Utc::now(),
335→                truncated,
336→                original_bytes,
337→            })
338→        }
339→        None => {
340→            // Timeout: append timeout notice to stderr
341→            let timeout_stderr = if stderr_str.is_empty() {
342→                format!("[timed out after {}s]", timeout.as_secs())
343→            } else {
344→                format!("{}\n[timed out after {}s]", stderr_str, timeout.as_secs())
345→            };
346→
347→            Ok(GateResult {
348→                passed: false,
349→                kind: GateKind::Command {
350→                    cmd: cmd.to_string(),
351→                },
352→                stdout: stdout_str,
353→                stderr: timeout_stderr,
354→                exit_code: None,
355→                duration_ms,
356→                timestamp: Utc::now(),
357→                truncated,
358→                original_bytes,
359→            })
360→        }
361→    }
362→}
363→
364→/// Return an immediately-passing result for AlwaysPass gates.
365→fn evaluate_always_pass() -> Result<GateResult> {
366→    Ok(GateResult {
367→        passed: true,
368→        kind: GateKind::AlwaysPass,
369→        stdout: String::new(),
370→        stderr: String::new(),
371→        exit_code: None,
372→        duration_ms: 0,
373→        timestamp: Utc::now(),
374→        truncated: false,
375→        original_bytes: None,
376→    })
377→}
378→
379→/// Truncate output, keeping the tail (since errors appear at end).
380→///
381→/// Returns `(possibly_truncated_string, was_truncated)`. If within
382→/// budget, returns the input unchanged. Otherwise, keeps the last
383→/// `max_bytes` bytes with a prepended truncation indicator, using
384→/// `str::ceil_char_boundary` for safe UTF-8 slicing.
385→fn truncate_output(output: &str, max_bytes: usize) -> (String, bool) {
386→    if output.len() <= max_bytes {
387→        return (output.to_string(), false);
388→    }
389→    let skip = output.len() - max_bytes;
390→    let start = output.ceil_char_boundary(skip);
391→    let truncated = format!(
392→        "[truncated, showing last {} bytes]\n{}",
393→        output.len() - start,
394→        &output[start..]
395→    );
396→    (truncated, true)
397→}
