 77→/// Check whether terminal colors should be used.
 78→///
 79→/// Returns `false` when the `NO_COLOR` environment variable is set
 80→/// (any value, including empty — per <https://no-color.org/>).
 81→fn colors_enabled() -> bool {
 82→    std::env::var("NO_COLOR").is_err()
 83→}
 84→
 85→/// Format a criterion type label, optionally with ANSI color.
 86→///
 87→/// "executable" (has a `cmd`) renders green; "descriptive" renders yellow.
 88→fn format_criteria_type(has_cmd: bool, color: bool) -> String {
 89→    if has_cmd {
 90→        if color {
 91→            "\x1b[32mexecutable\x1b[0m".to_string()
 92→        } else {
 93→            "executable".to_string()
 94→        }
 95→    } else if color {
 96→        "\x1b[33mdescriptive\x1b[0m".to_string()
 97→    } else {
 98→        "descriptive".to_string()
 99→    }
100→}
101→
102→/// Format "ok" with optional green color.
103→fn format_pass(color: bool) -> &'static str {
104→    if color { "\x1b[32mok\x1b[0m" } else { "ok" }
105→}
106→
107→/// Format "FAILED" with optional red color.
108→fn format_fail(color: bool) -> &'static str {
109→    if color {
110→        "\x1b[31mFAILED\x1b[0m"
111→    } else {
112→        "FAILED"
113→    }
114→}
115→
116→/// Format a number with optional ANSI color, only applying color when
117→/// the value is non-zero.
118→fn format_count(value: usize, ansi_code: &str, color: bool) -> String {
119→    if color && value > 0 {
120→        format!("{ansi_code}{value}\x1b[0m")
121→    } else {
122→        value.to_string()
123→    }
124→}
125→
126→/// Resolve the project root directory, exiting on failure.
127→fn project_root() -> std::path::PathBuf {
128→    std::env::current_dir().unwrap_or_else(|e| {
129→        eprintln!("Error: could not determine current directory: {e}");
130→        std::process::exit(1);
131→    })
132→}
133→
134→/// Handle `assay spec show <name> [--json]`.
135→fn handle_spec_show(name: &str, json: bool) {
136→    let root = project_root();
137→    let config = match assay_core::config::load(&root) {
138→        Ok(c) => c,
139→        Err(e) => {
140→            eprintln!("Error: {e}");
141→            std::process::exit(1);
142→        }
143→    };
144→    let specs_dir = root.join(".assay").join(&config.specs_dir);
145→    let spec_path = specs_dir.join(format!("{name}.toml"));
146→
147→    let spec = match assay_core::spec::load(&spec_path) {
148→        Ok(s) => s,
149→        Err(assay_core::AssayError::Io { source, .. })
150→            if source.kind() == std::io::ErrorKind::NotFound =>
151→        {
152→            eprintln!("Error: spec '{name}' not found in {}", config.specs_dir);
153→            std::process::exit(1);
154→        }
155→        Err(e) => {
156→            eprintln!("Error: {e}");
157→            std::process::exit(1);
158→        }
159→    };
160→
161→    if json {
162→        let output = serde_json::to_string_pretty(&spec).unwrap_or_else(|e| {
163→            eprintln!("Error: failed to serialize spec: {e}");
164→            std::process::exit(1);
165→        });
166→        println!("{output}");
167→        return;
168→    }
169→
170→    // Table output
171→    let color = colors_enabled();
172→
173→    println!("Spec: {}", spec.name);
174→    if !spec.description.is_empty() {
175→        println!("Description: {}", spec.description);
176→    }
177→    println!();
178→
179→    // Column widths: compute from data
180→    let num_width = spec.criteria.len().to_string().len().max(1);
181→    let name_width = spec
182→        .criteria
183→        .iter()
184→        .map(|c| c.name.len())
185→        .max()
186→        .unwrap_or(9)
187→        .max(9); // "Criterion" header
188→    let type_width = 11; // "descriptive" is longest at 11
189→
190→    // Header
191→    println!(
192→        "  {:<num_w$}  {:<name_w$}  {:<type_w$}  Command",
193→        "#",
194→        "Criterion",
195→        "Type",
196→        num_w = num_width,
197→        name_w = name_width,
198→        type_w = type_width,
199→    );
200→    // Separator
201→    println!(
202→        "  {:<num_w$}  {:<name_w$}  {:<type_w$}  {}",
203→        "\u{2500}".repeat(num_width),
204→        "\u{2500}".repeat(name_width),
205→        "\u{2500}".repeat(type_width),
206→        "\u{2500}".repeat(7),
207→        num_w = num_width,
208→        name_w = name_width,
209→        type_w = type_width,
210→    );
211→
212→    for (i, criterion) in spec.criteria.iter().enumerate() {
213→        let type_label = format_criteria_type(criterion.cmd.is_some(), color);
214→        let cmd_display = criterion.cmd.as_deref().unwrap_or("");
215→
216→        // When color is enabled the ANSI codes add non-printing characters,
217→        // so we need to pad the plain text width manually.
218→        if color {
219→            println!(
220→                "  {:<num_w$}  {:<name_w$}  {:<type_w$}  {cmd_display}",
221→                i + 1,
222→                criterion.name,
223→                type_label,
224→                num_w = num_width,
225→                name_w = name_width,
226→                // ANSI codes add 9 chars (\x1b[32m = 5 + \x1b[0m = 4) that don't display
227→                type_w = type_width + 9,
228→            );
229→        } else {
230→            println!(
231→                "  {:<num_w$}  {:<name_w$}  {:<type_w$}  {cmd_display}",
232→                i + 1,
233→                criterion.name,
234→                type_label,
235→                num_w = num_width,
236→                name_w = name_width,
237→                type_w = type_width,
238→            );
239→        }
240→    }
241→}
