243→/// Handle `assay spec list`.
244→fn handle_spec_list() {
245→    let root = project_root();
246→    let config = match assay_core::config::load(&root) {
247→        Ok(c) => c,
248→        Err(e) => {
249→            eprintln!("Error: {e}");
250→            std::process::exit(1);
251→        }
252→    };
253→    let specs_dir = root.join(".assay").join(&config.specs_dir);
254→
255→    let result = match assay_core::spec::scan(&specs_dir) {
256→        Ok(r) => r,
257→        Err(e) => {
258→            eprintln!("Error: {e}");
259→            std::process::exit(1);
260→        }
261→    };
262→
263→    // Print warnings for scan errors
264→    for err in &result.errors {
265→        eprintln!("Warning: {err}");
266→    }
267→
268→    if result.specs.is_empty() {
269→        println!("No specs found in {}", config.specs_dir);
270→        return;
271→    }
272→
273→    // Compute name column width for alignment
274→    let name_width = result
275→        .specs
276→        .iter()
277→        .map(|(slug, _)| slug.len())
278→        .max()
279→        .unwrap_or(0);
280→
281→    println!("Specs:");
282→    for (slug, spec) in &result.specs {
283→        if spec.description.is_empty() {
284→            println!("  {slug}");
285→        } else {
286→            println!(
287→                "  {:<width$}  {}",
288→                slug,
289→                spec.description,
290→                width = name_width
291→            );
292→        }
293→    }
294→}
