312→            if source.kind() == std::io::ErrorKind::NotFound =>
313→        {
314→            eprintln!("Error: spec '{name}' not found in {}", config.specs_dir);
315→            std::process::exit(1);
316→        }
317→        Err(e) => {
318→            eprintln!("Error: {e}");
319→            std::process::exit(1);
320→        }
321→    };
322→
323→    // Resolve working directory: config gates.working_dir > project root
324→    let working_dir = match config.gates.as_ref().and_then(|g| g.working_dir.as_deref()) {
325→        Some(dir) => {
326→            let path = std::path::Path::new(dir);
327→            if path.is_absolute() {
328→                path.to_path_buf()
329→            } else {
330→                root.join(path)
331→            }
332→        }
333→        None => root.clone(),
334→    };
335→
336→    // Extract config timeout
337→    let config_timeout = config.gates.as_ref().map(|g| g.default_timeout);
338→
339→    // JSON output path: evaluate all at once, serialize, print
340→    if json {
341→        let summary =
342→            assay_core::gate::evaluate_all(&spec, &working_dir, cli_timeout, config_timeout);
343→        let output = serde_json::to_string_pretty(&summary).unwrap_or_else(|e| {
344→            eprintln!("Error: failed to serialize gate results: {e}");
345→            std::process::exit(1);
346→        });
347→        println!("{output}");
348→        if summary.failed > 0 {
349→            std::process::exit(1);
350→        }
351→        return;
352→    }
353→
354→    // Streaming display path: iterate criteria manually for live progress
355→    let color = colors_enabled();
356→
357→    let mut passed = 0usize;
358→    let mut failed = 0usize;
359→    let mut skipped = 0usize;
360→    let executable_count = spec.criteria.iter().filter(|c| c.cmd.is_some()).count();
361→
362→    if executable_count == 0 {
363→        println!("No executable criteria found");
364→        return;
365→    }
366→
367→    for criterion in &spec.criteria {
368→        // Descriptive-only criteria: skip silently during streaming
369→        if criterion.cmd.is_none() {
370→            skipped += 1;
371→            continue;
372→        }
373→
374→        // Show "running" state (overwritable line on stderr)
375→        if color {
376→            eprint!("\r\x1b[K  {} ... running", criterion.name);
377→        } else {
378→            eprint!("\r  {} ... running", criterion.name);
379→        }
380→
381→        let timeout =
382→            assay_core::gate::resolve_timeout(cli_timeout, criterion.timeout, config_timeout);
383→
384→        match assay_core::gate::evaluate(criterion, &working_dir, timeout) {
385→            Ok(result) => {
386→                let status_label = if result.passed {
387→                    passed += 1;
388→                    format_pass(color)
389→                } else {
390→                    failed += 1;
391→                    format_fail(color)
392→                };
393→
394→                // Replace the running line with final status
395→                if color {
396→                    eprintln!("\r\x1b[K  {} ... {}", criterion.name, status_label);
397→                } else {
398→                    eprintln!("\r  {} ... {}", criterion.name, status_label);
399→                }
400→
401→                // Show evidence for failures (always) or all criteria (--verbose)
402→                if !result.passed || verbose {
403→                    print_evidence(&result.stdout, &result.stderr, result.truncated, color);
404→                }
405→            }
406→            Err(err) => {
407→                failed += 1;
408→
409→                // Replace the running line with FAILED
410→                if color {
411→                    eprintln!("\r\x1b[K  {} ... {}", criterion.name, format_fail(color));
412→                } else {
413→                    eprintln!("\r  {} ... {}", criterion.name, format_fail(color));
414→                }
415→                eprintln!("    error: {err}");
416→            }
417→        }
418→    }
419→
420→    // Summary line (stdout for capturability)
421→    let total = passed + failed + skipped;
422→    let passed_str = format_count(passed, "\x1b[32m", color);
423→    let failed_str = format_count(failed, "\x1b[31m", color);
424→    let skipped_str = format_count(skipped, "\x1b[33m", color);
425→
426→    println!();
427→    println!(
428→        "Results: {passed_str} passed, {failed_str} failed, {skipped_str} skipped (of {total} total)"
429→    );
430→
431→    if failed > 0 {
432→        std::process::exit(1);
433→    }
434→}
435→
436→/// Print evidence (stdout/stderr) for a gate result.
437→///
438→/// Multi-line output is indented with 4 spaces per line. If the output
439→/// was truncated, a note is appended.
440→fn print_evidence(stdout: &str, stderr: &str, truncated: bool, color: bool) {
441→    let stdout = stdout.trim();
442→    let stderr = stderr.trim();
443→
444→    if !stdout.is_empty() {
445→        eprintln!("    stdout:");
446→        for line in stdout.lines() {
447→            eprintln!("      {line}");
448→        }
449→    }
450→    if !stderr.is_empty() {
451→        eprintln!("    stderr:");
452→        for line in stderr.lines() {
453→            eprintln!("      {line}");
454→        }
455→    }
456→    if truncated {
457→        let note = if color {
458→            "\x1b[33m[output truncated]\x1b[0m"
459→        } else {
460→            "[output truncated]"
461→        };
462→        eprintln!("    {note}");
463→    }
464→}
