466→/// Initialize tracing to stderr for MCP server operation.
467→///
468→/// Default level is `warn`. Override via `RUST_LOG` environment variable.
469→/// Stdout is reserved for JSON-RPC — all diagnostics go to stderr.
470→fn init_mcp_tracing() {
471→    use tracing_subscriber::EnvFilter;
472→
473→    let filter = EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("warn"));
474→
475→    if let Err(e) = tracing_subscriber::fmt()
476→        .with_env_filter(filter)
477→        .with_writer(std::io::stderr)
478→        .with_ansi(false)
479→        .try_init()
480→    {
481→        eprintln!("[assay] warning: failed to initialize tracing: {e}");
482→    }
483→}
484→
485→#[tokio::main]
486→async fn main() {
487→    let cli = Cli::parse();
488→
489→    match cli.command {
490→        Some(Command::Init { name }) => {
491→            let root = std::env::current_dir().unwrap_or_else(|e| {
492→                eprintln!("Error: could not determine current directory: {e}");
493→                std::process::exit(1);
494→            });
495→            let options = assay_core::init::InitOptions { name };
496→            match assay_core::init::init(&root, &options) {
497→                Ok(result) => {
498→                    println!("  Created assay project `{}`", result.project_name);
499→                    for path in &result.created_files {
500→                        let display = path.strip_prefix(&root).unwrap_or(path);
501→                        println!("    created {}", display.display());
502→                    }
503→                }
504→                Err(e) => {
505→                    eprintln!("Error: {e}");
506→                    std::process::exit(1);
507→                }
508→            }
509→        }
510→        Some(Command::Mcp { command }) => match command {
511→            McpCommand::Serve => {
512→                init_mcp_tracing();
513→                if let Err(e) = assay_mcp::serve().await {
514→                    eprintln!("Error: {e:?}");
515→                    std::process::exit(1);
516→                }
517→            }
518→        },
519→        Some(Command::Spec { command }) => match command {
520→            SpecCommand::Show { name, json } => handle_spec_show(&name, json),
521→            SpecCommand::List => handle_spec_list(),
522→        },
523→        Some(Command::Gate { command }) => match command {
524→            GateCommand::Run {
525→                name,
526→                timeout,
527→                verbose,
528→                json,
529→            } => {
530→                handle_gate_run(&name, timeout, verbose, json);
531→            }
532→        },
533→        None => {
534→            println!("assay {}", env!("CARGO_PKG_VERSION"));
535→        }
536→    }
537→}
