  1→//! Criterion types for defining acceptance criteria on specs.
  2→
  3→use schemars::JsonSchema;
  4→use serde::{Deserialize, Serialize};
  5→
  6→/// A single acceptance criterion attached to a spec.
  7→///
  8→/// Each criterion has a name, description, and an optional shell command
  9→/// that can verify it programmatically. When `cmd` is `None`, the criterion
 10→/// is evaluated manually (or in future phases, via an agent `prompt` field).
 11→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize, JsonSchema)]
 12→#[serde(deny_unknown_fields)]
 13→pub struct Criterion {
 14→    /// Human-readable name for this criterion.
 15→    pub name: String,
 16→
 17→    /// Detailed description of what this criterion checks.
 18→    pub description: String,
 19→
 20→    /// Optional shell command to verify this criterion.
 21→    /// Omitted from serialized output when `None`.
 22→    // Forward-compatible: a future `prompt` field will support agent-based evaluation.
 23→    #[serde(skip_serializing_if = "Option::is_none", default)]
 24→    pub cmd: Option<String>,
 25→
 26→    /// Optional timeout in seconds for this criterion's command.
 27→    /// Overrides the global default but is overridden by CLI `--timeout`.
 28→    #[serde(skip_serializing_if = "Option::is_none", default)]
 29→    pub timeout: Option<u64>,
 30→}
 31→
 32→inventory::submit! {
 33→    crate::schema_registry::SchemaEntry {
 34→        name: "criterion",
 35→        generate: || schemars::schema_for!(Criterion),
 36→    }
 37→}
