  1→//! Configuration loading and validation.
  2→//!
  3→//! Handles reading, parsing, and validating Assay project configuration
  4→//! from files and environment.
  5→
  6→use std::fmt;
  7→use std::path::Path;
  8→
  9→use assay_types::Config;
 10→
 11→use crate::error::{AssayError, Result};
 12→
 13→/// A single validation issue in a config file.
 14→#[derive(Debug, Clone)]
 15→pub struct ConfigError {
 16→    /// The field path (e.g., "project_name", "[gates].default_timeout").
 17→    pub field: String,
 18→    /// What's wrong.
 19→    pub message: String,
 20→}
 21→
 22→impl fmt::Display for ConfigError {
 23→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
 24→        write!(f, "{}: {}", self.field, self.message)
 25→    }
 26→}
 27→
 28→/// Parse a config from a TOML string without validation.
 29→///
 30→/// Returns the raw `toml::de::Error` on failure, preserving line/column
 31→/// information. Callers that need validation should use [`load()`] instead.
 32→pub fn from_str(s: &str) -> std::result::Result<Config, toml::de::Error> {
 33→    toml::from_str(s)
 34→}
 35→
 36→/// Validate a parsed config for semantic correctness.
 37→///
 38→/// Collects **all** validation errors at once so the user can fix
 39→/// everything in a single pass. Returns `Ok(())` when valid,
 40→/// `Err(errors)` with every issue found otherwise.
 41→pub fn validate(config: &Config) -> std::result::Result<(), Vec<ConfigError>> {
 42→    let mut errors = Vec::new();
 43→
 44→    if config.project_name.trim().is_empty() {
 45→        errors.push(ConfigError {
 46→            field: "project_name".into(),
 47→            message: "required, must not be empty".into(),
 48→        });
 49→    }
 50→
 51→    if config.specs_dir.trim().is_empty() {
 52→        errors.push(ConfigError {
 53→            field: "specs_dir".into(),
 54→            message: "required, must not be empty".into(),
 55→        });
 56→    }
 57→
 58→    if let Some(gates) = &config.gates
 59→        && gates.default_timeout == 0
 60→    {
 61→        errors.push(ConfigError {
 62→            field: "[gates].default_timeout".into(),
 63→            message: "must be a positive integer".into(),
 64→        });
 65→    }
 66→
 67→    if errors.is_empty() {
 68→        Ok(())
 69→    } else {
 70→        Err(errors)
 71→    }
 72→}
 73→
 74→/// Load and validate a config from `.assay/config.toml` relative to `root`.
 75→///
 76→/// Reads the file, parses it as TOML, and validates the result. Wraps
 77→/// parse errors in [`AssayError::ConfigParse`] (with file path) and
 78→/// validation errors in [`AssayError::ConfigValidation`].
 79→pub fn load(root: &Path) -> Result<Config> {
 80→    let path = root.join(".assay").join("config.toml");
 81→
 82→    let content = std::fs::read_to_string(&path).map_err(|source| AssayError::Io {
 83→        operation: "reading config".into(),
 84→        path: path.clone(),
 85→        source,
 86→    })?;
 87→
 88→    let config: Config = toml::from_str(&content).map_err(|e| AssayError::ConfigParse {
 89→        path: path.clone(),
 90→        message: e.to_string(),
 91→    })?;
 92→
 93→    if let Err(errors) = validate(&config) {
 94→        return Err(AssayError::ConfigValidation { path, errors });
 95→    }
 96→
 97→    Ok(config)
 98→}
