 71→/// Evaluate a single criterion as a gate.
 72→///
 73→/// Derives `GateKind` from criterion fields: if `cmd` is `Some`, it's
 74→/// `GateKind::Command`; if `cmd` is `None`, it's `GateKind::AlwaysPass`.
 75→///
 76→/// `working_dir` is required — this function never inherits the process CWD.
 77→/// `timeout` is the maximum wall-clock time for the command to complete.
 78→///
 79→/// # Async Usage
 80→///
 81→/// This function is synchronous. From async code, use:
 82→/// ```ignore
 83→/// tokio::task::spawn_blocking(move || gate::evaluate(&criterion, &dir, timeout)).await?
 84→/// ```
 85→pub fn evaluate(
 86→    criterion: &Criterion,
 87→    working_dir: &Path,
 88→    timeout: Duration,
 89→) -> Result<GateResult> {
 90→    match &criterion.cmd {
 91→        Some(cmd) => evaluate_command(cmd, working_dir, timeout),
 92→        None => evaluate_always_pass(),
 93→    }
 94→}
 95→
 96→/// Evaluate all criteria in a spec sequentially.
 97→///
 98→/// Skips criteria without `cmd` (records as skipped in summary). Uses
 99→/// [`resolve_timeout`] for each criterion's timeout. Individual criterion
100→/// failures are captured in `GateResult`, not propagated as errors. If
101→/// [`evaluate`] returns an `Err` (spawn failure), it's captured as a
102→/// failed `CriterionResult` with error details in stderr.
103→///
104→/// # Async Usage
105→///
106→/// This function is synchronous. From async code, use:
107→/// ```ignore
108→/// tokio::task::spawn_blocking(move || {
109→///     gate::evaluate_all(&spec, &dir, cli_timeout, config_timeout)
110→/// }).await?
111→/// ```
112→pub fn evaluate_all(
113→    spec: &Spec,
114→    working_dir: &Path,
115→    cli_timeout: Option<u64>,
116→    config_timeout: Option<u64>,
117→) -> GateRunSummary {
118→    let start = Instant::now();
119→    let mut results = Vec::with_capacity(spec.criteria.len());
120→    let mut passed = 0usize;
121→    let mut failed = 0usize;
122→    let mut skipped = 0usize;
123→
124→    for criterion in &spec.criteria {
125→        if criterion.cmd.is_none() {
126→            skipped += 1;
127→            results.push(CriterionResult {
128→                criterion_name: criterion.name.clone(),
129→                result: None,
130→            });
131→            continue;
132→        }
133→
134→        let timeout = resolve_timeout(cli_timeout, criterion.timeout, config_timeout);
135→
136→        match evaluate(criterion, working_dir, timeout) {
137→            Ok(gate_result) => {
138→                if gate_result.passed {
139→                    passed += 1;
140→                } else {
141→                    failed += 1;
142→                }
143→                results.push(CriterionResult {
144→                    criterion_name: criterion.name.clone(),
145→                    result: Some(gate_result),
146→                });
147→            }
148→            Err(err) => {
149→                failed += 1;
150→                results.push(CriterionResult {
151→                    criterion_name: criterion.name.clone(),
152→                    result: Some(GateResult {
153→                        passed: false,
154→                        kind: GateKind::Command {
155→                            cmd: criterion.cmd.clone().unwrap_or_default(),
156→                        },
157→                        stdout: String::new(),
158→                        stderr: format!("gate evaluation error: {err}"),
159→                        exit_code: None,
160→                        duration_ms: 0,
161→                        timestamp: Utc::now(),
162→                        truncated: false,
163→                        original_bytes: None,
164→                    }),
165→                });
166→            }
167→        }
168→    }
169→
170→    GateRunSummary {
171→        spec_name: spec.name.clone(),
172→        results,
173→        passed,
174→        failed,
175→        skipped,
176→        total_duration_ms: start.elapsed().as_millis() as u64,
177→    }
178→}
