180→/// Resolve the effective timeout from three tiers of configuration.
181→///
182→/// Precedence: CLI `--timeout` > per-criterion `timeout` > config global > 300s default.
183→/// Enforces a minimum floor of 1 second.
184→pub fn resolve_timeout(
185→    cli_timeout: Option<u64>,
186→    criterion_timeout: Option<u64>,
187→    config_timeout: Option<u64>,
188→) -> Duration {
189→    let seconds = cli_timeout
190→        .or(criterion_timeout)
191→        .or(config_timeout)
192→        .unwrap_or(300);
193→    Duration::from_secs(seconds.max(MIN_TIMEOUT_SECS))
194→}
